import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useToast } from "@/hooks/use-toast";

// Track comments posted in this session - resets on page refresh
// This allows flagged comments to show during the current session
export const sessionPostedCommentIds = new Set<string>();

export interface Comment {
  id: string;
  user_id: string;
  target_id: string;
  target_type: string;
  content: string;
  rating_value?: number | null;
  price_range?: string | null;
  image_url?: string;
  parent_id?: string;
  edited: boolean;
  moderation_status?: "pending" | "approved" | "flagged";
  created_at: string;
  updated_at: string;
  profiles?: {
    display_name: string;
    avatar_url?: string;
  };
  replies?: Comment[];
}

export const useComments = (targetId: string, targetType: string = "restaurant", options?: { enabled?: boolean }) => {
  const { user } = useAuth();
  
  return useQuery({
    queryKey: ["comments", targetId, targetType],
    enabled: (options?.enabled !== false) && !!targetId,
    queryFn: async () => {
      // Fetch all comments (both main and replies) in a single query
      let query = supabase
        .from("comments")
        .select("*")
        .eq("target_id", targetId)
        .eq("target_type", targetType)
        .order("created_at", { ascending: false });

      const { data: allComments, error } = await query;

      if (error) throw error;
      if (!allComments || allComments.length === 0) return [];

      // Filter comments:
      // 1. Show approved comments to everyone
      // 2. Show user's own pending comments
      // 3. Show user's own flagged comments ONLY if posted in this session (before refresh)
      const filteredComments = allComments.filter(comment => 
        comment.moderation_status === "approved" || 
        (user && comment.user_id === user.id && comment.moderation_status === "pending") ||
        (user && comment.user_id === user.id && comment.moderation_status === "flagged" && sessionPostedCommentIds.has(comment.id))
      );

      // Get unique user IDs from filtered comments
      const userIds = [...new Set(filteredComments.map(c => c.user_id))];
      
      // Use secure function to get only public profile data (display_name, avatar_url)
      const { data: profiles } = await supabase
        .rpc("get_public_profiles", { user_ids: userIds });

      // Create a profile lookup map
      const profileMap = new Map(
        (profiles || []).map((p: { id: string; display_name: string; avatar_url: string }) => 
          [p.id, { display_name: p.display_name, avatar_url: p.avatar_url }]
        )
      );

      // Separate main comments and replies from filtered comments
      const mainComments = filteredComments.filter(c => !c.parent_id);
      const replies = filteredComments.filter(c => c.parent_id);

      // Group replies by parent_id
      const repliesByParentId = new Map<string, typeof allComments>();
      replies.forEach(reply => {
        const parentId = reply.parent_id!;
        if (!repliesByParentId.has(parentId)) {
          repliesByParentId.set(parentId, []);
        }
        repliesByParentId.get(parentId)!.push(reply);
      });

      // Build the comment tree
      const commentsWithDetails: Comment[] = mainComments.map(comment => ({
        ...comment,
        moderation_status: comment.moderation_status as "pending" | "approved" | "flagged" | undefined,
        profiles: profileMap.get(comment.user_id),
        replies: (repliesByParentId.get(comment.id) || [])
          .sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime())
          .map(reply => ({
            ...reply,
            moderation_status: reply.moderation_status as "pending" | "approved" | "flagged" | undefined,
            profiles: profileMap.get(reply.user_id),
          })),
      }));

      return commentsWithDetails;
    },
    staleTime: 30000, // Cache for 30 seconds
  });
};

export const useAddComment = () => {
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      targetId,
      targetType,
      content,
      ratingValue,
      priceRange,
      imageUrl,
      parentId,
    }: {
      targetId: string;
      targetType: string;
      content: string;
      ratingValue?: number;
      priceRange?: string;
      imageUrl?: string;
      parentId?: string;
    }) => {
      if (!user) throw new Error("User not authenticated");

      const insertData: any = {
        user_id: user.id,
        target_id: targetId,
        target_type: targetType,
        content,
        parent_id: parentId,
        moderation_status: "pending", // Start with pending until AI review
      };

      // Only add rating and price range for non-reply comments
      if (!parentId) {
        if (ratingValue) insertData.rating_value = ratingValue;
        if (priceRange) insertData.price_range = priceRange;
      }

      if (imageUrl) insertData.image_url = imageUrl;

      const { data, error } = await supabase
        .from("comments")
        .insert(insertData)
        .select()
        .single();

      if (error) throw error;

      // Trigger AI moderation asynchronously
      // Pass target info for user notification
      try {
        const { data: moderationResult, error: moderationError } = await supabase.functions.invoke("moderate-comment", {
          body: {
            comment_id: data.id,
            content,
            user_id: user.id,
            sensitive_word_detected: false,
            target_id: targetId,
            target_type: targetType,
          },
        });

        if (moderationError) {
          console.error("AI moderation error:", moderationError);
          // If moderation fails, auto-approve (fallback to allow comment)
          await supabase
            .from("comments")
            .update({ moderation_status: "approved" })
            .eq("id", data.id);
        }
      } catch (e) {
        console.error("Failed to invoke AI moderation:", e);
        // If moderation fails, auto-approve (fallback to allow comment)
        await supabase
          .from("comments")
          .update({ moderation_status: "approved" })
          .eq("id", data.id);
      }

      return data;
    },
    onSuccess: (data, variables) => {
      // Track this comment ID for session-based visibility of flagged comments
      if (data?.id) {
        sessionPostedCommentIds.add(data.id);
      }
      queryClient.invalidateQueries({ queryKey: ["comments", variables.targetId, variables.targetType] });
      queryClient.invalidateQueries({ queryKey: ["restaurants"] });
      queryClient.invalidateQueries({ queryKey: ["restaurant", variables.targetId] });
      // Invalidate community post data to update comments_count
      if (variables.targetType === "post") {
        queryClient.invalidateQueries({ queryKey: ["community-post", variables.targetId] });
        queryClient.invalidateQueries({ queryKey: ["community-posts"] });
      }
      // No toast on success - only notify on failure
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to add comment",
        variant: "destructive",
      });
    },
  });
};

export const useUpdateComment = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      commentId,
      content,
    }: {
      commentId: string;
      content: string;
    }) => {
      const { data, error } = await supabase
        .from("comments")
        .update({ content, edited: true })
        .eq("id", commentId)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["comments"] });
      toast({
        title: t("common.success", "Success"),
        description: t("toast.commentUpdated", "Comment updated successfully"),
      });
    },
    onError: () => {
      toast({
        title: t("common.error", "Error"),
        description: t("toast.commentUpdateFailed", "Failed to update comment"),
        variant: "destructive",
      });
    },
  });
};

export const useDeleteComment = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (commentId: string) => {
      const { error } = await supabase
        .from("comments")
        .delete()
        .eq("id", commentId);

      if (error) throw error;
    },
    onSuccess: (_data, commentId) => {
      queryClient.invalidateQueries({ queryKey: ["comments"] });
      // Also invalidate community posts to update comments_count
      queryClient.invalidateQueries({ queryKey: ["community-post"] });
      queryClient.invalidateQueries({ queryKey: ["community-posts"] });
      toast({
        title: t("common.success", "Success"),
        description: t("toast.commentDeleted", "Comment deleted successfully"),
      });
    },
    onError: () => {
      toast({
        title: t("common.error", "Error"),
        description: t("toast.commentDeleteFailed", "Failed to delete comment"),
        variant: "destructive",
      });
    },
  });
};
