import { useState } from "react";
import TranslateButton from "@/components/TranslateButton";

interface TranslatableTextProps {
  text: string;
  className?: string;
  renderContent?: (displayText: string) => React.ReactNode;
}

const TranslatableText = ({ text, className, renderContent }: TranslatableTextProps) => {
  const [translatedText, setTranslatedText] = useState<string | null>(null);

  const displayText = translatedText || text;

  return (
    <div className={className}>
      {renderContent ? (
        renderContent(displayText)
      ) : (
        <p className="text-xs sm:text-sm text-foreground break-words">
          {displayText}
        </p>
      )}
      <TranslateButton 
        text={text} 
        onTranslation={setTranslatedText}
        className="mt-2"
      />
    </div>
  );
};

export default TranslatableText;
