import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { ShieldAlert, X, Plus } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";

interface ReportDialogProps {
  targetType: "comment" | "restaurant" | "activity" | "user";
  targetId: string;
  trigger?: React.ReactNode;
  onLoginRequired?: () => void;
}

const ReportDialog = ({ targetType, targetId, trigger, onLoginRequired }: ReportDialogProps) => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [open, setOpen] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [reason, setReason] = useState<string>("");
  const [description, setDescription] = useState("");
  const [contact, setContact] = useState(user?.email || "");
  const [evidenceUrls, setEvidenceUrls] = useState<string[]>([""]);
  const [evidenceImages, setEvidenceImages] = useState<File[]>([]);
  const [uploadingImages, setUploadingImages] = useState(false);

  // Email verification states for non-logged-in users
  const [verificationStep, setVerificationStep] = useState<"form" | "verify" | "submitting">("form");
  const [verificationCode, setVerificationCode] = useState("");
  const [resendCountdown, setResendCountdown] = useState(0);
  const [isSendingCode, setIsSendingCode] = useState(false);

  // Update contact email when user changes or dialog opens
  const handleOpenChange = (newOpen: boolean) => {
    // If trying to open and user is not logged in, trigger login required callback
    if (newOpen && !user) {
      onLoginRequired?.();
      return;
    }
    
    setOpen(newOpen);
    if (newOpen && user?.email) {
      setContact(user.email);
    }
    if (!newOpen) {
      // Reset verification step when dialog closes
      setVerificationStep("form");
      setVerificationCode("");
      setResendCountdown(0);
    }
  };

  // Countdown timer for resend button
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (resendCountdown > 0) {
      timer = setTimeout(() => setResendCountdown(resendCountdown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [resendCountdown]);

  const reasons = [
    "spam",
    "harassment",
    "inappropriate_content",
    "misinformation",
    "copyright",
    "fraud",
    "hate_speech",
    "violence",
    "other",
  ];

  const addEvidenceUrl = () => {
    setEvidenceUrls([...evidenceUrls, ""]);
  };

  const removeEvidenceUrl = (index: number) => {
    setEvidenceUrls(evidenceUrls.filter((_, i) => i !== index));
  };

  const updateEvidenceUrl = (index: number, value: string) => {
    const newUrls = [...evidenceUrls];
    newUrls[index] = value;
    setEvidenceUrls(newUrls);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    
    // 验证文件大小（5MB）
    const oversizedFiles = files.filter(f => f.size > 5 * 1024 * 1024);
    if (oversizedFiles.length > 0) {
      toast.error(t("report.imageTooLarge"));
      return;
    }
    
    // 验证文件类型
    const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
    const invalidFiles = files.filter(f => !validTypes.includes(f.type));
    if (invalidFiles.length > 0) {
      toast.error(t("report.invalidImageType"));
      return;
    }
    
    setEvidenceImages(prev => [...prev, ...files]);
  };

  const removeImage = (index: number) => {
    setEvidenceImages(prev => prev.filter((_, i) => i !== index));
  };

  const uploadImages = async (): Promise<string[]> => {
    if (evidenceImages.length === 0) return [];
    
    setUploadingImages(true);
    const uploadedUrls: string[] = [];
    
    try {
      for (const file of evidenceImages) {
        const fileExt = file.name.split('.').pop();
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const filePath = `${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('report-evidence')
          .upload(filePath, file);

        if (uploadError) throw uploadError;

        // 获取文件的完整路径
        const { data } = supabase.storage
          .from('report-evidence')
          .getPublicUrl(filePath);
        
        uploadedUrls.push(data.publicUrl);
      }
      
      return uploadedUrls;
    } catch (error) {
      console.error('Error uploading images:', error);
      throw error;
    } finally {
      setUploadingImages(false);
    }
  };

  const sendVerificationCode = async () => {
    if (!contact.trim()) {
      toast.error(t("report.contactRequired"));
      return;
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(contact)) {
      toast.error(t("report.invalidEmail"));
      return;
    }

    setIsSendingCode(true);
    try {
      const { error } = await supabase.functions.invoke("send-verification-code", {
        body: { email: contact },
      });

      if (error) {
        toast.error(t("auth.verificationCodeFailed"));
        console.error(error);
        return;
      }

      setVerificationStep("verify");
      toast.success(t("auth.verificationCodeSent"));
      setResendCountdown(30);
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
    } finally {
      setIsSendingCode(false);
    }
  };

  const handleResendCode = async () => {
    if (resendCountdown > 0) return;
    await sendVerificationCode();
  };

  const verifyEmailCode = async () => {
    if (verificationCode.length !== 4) {
      toast.error(t("auth.invalidVerificationCode"));
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: verifyResult, error: verifyError } = await supabase.functions.invoke(
        "verify-email-code",
        {
          body: {
            email: contact,
            code: verificationCode,
          },
        }
      );

      if (verifyError || !verifyResult?.success) {
        const errorMessage = verifyResult?.error;
        if (errorMessage === "This verification code has already been used") {
          toast.error(t("auth.verificationCodeUsed"));
        } else {
          toast.error(verifyResult?.error || t("auth.invalidVerificationCode"));
        }
        setIsSubmitting(false);
        return;
      }

      // Verification successful, change to submitting state
      setVerificationStep("submitting");
      
      // Submit report
      await handleConfirmSubmit();
    } catch (error: any) {
      toast.error(error.message || t("error.general"));
      setIsSubmitting(false);
    }
  };

  const handleSubmit = async () => {
    if (!reason) {
      toast.error(t("report.reasonPlaceholder"));
      return;
    }

    if (!description || description.length < 20) {
      toast.error(t("report.detailsMin"));
      return;
    }

    // 联系邮箱必填
    if (!contact.trim()) {
      toast.error(t("report.contactRequired"));
      return;
    }

    // 验证邮箱格式
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(contact)) {
      toast.error(t("report.invalidEmail"));
      return;
    }

    // 至少需要一个证据（链接或图片）
    const filteredUrls = evidenceUrls.filter((url) => url.trim() !== "");
    if (filteredUrls.length === 0 && evidenceImages.length === 0) {
      toast.error(t("report.evidenceRequired"));
      return;
    }

    // If user is not logged in, require email verification
    if (!user) {
      await sendVerificationCode();
    } else {
      // If user is logged in, show confirmation dialog
      setShowConfirm(true);
    }
  };

  const handleConfirmSubmit = async () => {
    setIsSubmitting(true);
    try {
      // 上传图片
      let uploadedImageUrls: string[] = [];
      try {
        uploadedImageUrls = await uploadImages();
      } catch (error) {
        toast.error(t("report.imageUploadFailed"));
        setIsSubmitting(false);
        return;
      }

      const filteredUrls = evidenceUrls.filter((url) => url.trim() !== "");
      const allEvidenceUrls = [...filteredUrls, ...uploadedImageUrls];

      // Prepare report data
      const reportData = {
        reporter_id: user?.id || null,
        target_type: targetType,
        target_id: targetId,
        reason,
        description,
        evidence_urls: allEvidenceUrls,
        reporter_contact: contact,
      };

      console.log("Attempting to insert report:", reportData);

      // Insert report into database
      const { data: report, error: reportError } = await supabase
        .from("reports")
        .insert(reportData as any)
        .select()
        .single();

      console.log("Insert result:", { report, error: reportError });

      if (reportError) throw reportError;

      // Get reporter info (if logged in)
      let reporterName = "Anonymous";
      let reporterEmail = contact;
      
      if (user) {
        const { data: profile } = await supabase
          .from("profiles")
          .select("display_name")
          .eq("id", user.id)
          .single();
        
        reporterName = profile?.display_name || "Unknown";
        reporterEmail = user.email || contact;
      }

      // Send email notification
      await supabase.functions.invoke("send-report-email", {
        body: {
          reportId: report.id,
          reporterName,
          reporterEmail,
          targetType,
          targetId,
          reason,
          description,
          evidenceUrls: allEvidenceUrls.length > 0 ? allEvidenceUrls : undefined,
          reporterContact: contact || undefined,
        },
      });

      // Show detailed success message
      const reportReference = report.id.substring(0, 8).toUpperCase();
      toast.success(
        t("report.successDetailed", { reference: reportReference }),
        {
          description: t("report.successDescription"),
          duration: 8000,
        }
      );
      
      setOpen(false);
      setShowConfirm(false);
      
      // Reset form
      setReason("");
      setDescription("");
      if (!user) {
        setContact("");
      }
      setEvidenceUrls([""]);
      setEvidenceImages([]);
      setVerificationStep("form");
      setVerificationCode("");
    } catch (error: any) {
      console.error("Error submitting report:", error);
      toast.error(t("report.failed"));
    } finally {
      setIsSubmitting(false);
    }
  };

  const getTitle = () => {
    switch (targetType) {
      case "comment":
        return t("report.reportComment");
      case "restaurant":
        return t("report.reportRestaurant");
      case "activity":
        return t("report.reportActivity");
      case "user":
        return t("report.reportUser");
      default:
        return t("report.title");
    }
  };

  return (
    <>
      <Dialog open={open} onOpenChange={handleOpenChange}>
        <DialogTrigger asChild>
          {trigger || (
            <Button variant="ghost" size="sm">
              <ShieldAlert className="w-4 h-4 mr-2" />
              {t("report.title")}
            </Button>
          )}
        </DialogTrigger>
        <DialogContent className="max-w-[90vw] sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{getTitle()}</DialogTitle>
            <DialogDescription>
              {verificationStep === "verify" 
                ? t("auth.verificationCodeSent") 
                : t("report.description")}
            </DialogDescription>
          </DialogHeader>

          {verificationStep === "form" ? (
            <>
              <div className="space-y-4 py-4">
                <div className="space-y-2">
                  <Label htmlFor="reason">{t("report.reason")}</Label>
                  <Select value={reason} onValueChange={setReason}>
                    <SelectTrigger>
                      <SelectValue placeholder={t("report.reasonPlaceholder")} />
                    </SelectTrigger>
                    <SelectContent>
                      {reasons.map((r) => (
                        <SelectItem key={r} value={r}>
                          {t(`report.reasons.${r}`)}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="description">{t("report.detailsLabel")}</Label>
                  <Textarea
                    id="description"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder={t("report.detailsPlaceholder")}
                    rows={5}
                    className="resize-none"
                  />
                  <p className="text-xs text-muted-foreground">
                    {description.length}/20 {t("common.characters")}
                  </p>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="contact">
                    {t("report.contactLabel")}
                    <span className="text-destructive ml-1">*</span>
                  </Label>
                  <Input
                    id="contact"
                    type="email"
                    value={contact}
                    onChange={(e) => setContact(e.target.value)}
                    placeholder={t("report.contactPlaceholder")}
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label>
                    {t("report.evidenceLabel")}
                    <span className="text-destructive ml-1">*</span>
                  </Label>
                  <p className="text-xs text-muted-foreground mb-2">
                    {t("report.evidenceRequiredNote")}
                  </p>
                  
                  {/* 图片上传 */}
                  <div className="space-y-2">
                    <Label htmlFor="image-upload" className="text-sm font-medium">
                      {t("report.uploadImages")}
                    </Label>
                    <div className="flex flex-wrap gap-2 mb-2">
                      {evidenceImages.map((file, index) => (
                        <div key={index} className="relative group">
                          <img
                            src={URL.createObjectURL(file)}
                            alt={`Evidence ${index + 1}`}
                            className="w-20 h-20 object-cover rounded border"
                          />
                          <Button
                            type="button"
                            variant="destructive"
                            size="icon"
                            className="absolute -top-2 -right-2 h-6 w-6 opacity-0 group-hover:opacity-100 transition-opacity"
                            onClick={() => removeImage(index)}
                          >
                            <X className="w-3 h-3" />
                          </Button>
                        </div>
                      ))}
                    </div>
                    <Input
                      id="image-upload"
                      type="file"
                      accept="image/jpeg,image/png,image/webp,image/gif"
                      multiple
                      onChange={handleImageSelect}
                      className="cursor-pointer"
                    />
                    <p className="text-xs text-muted-foreground">
                      {t("report.imageUploadHint")}
                    </p>
                  </div>

                  {/* URL 链接 */}
                  <div className="space-y-2 pt-2">
                    <Label className="text-sm font-medium">
                      {t("report.evidenceUrls")}
                    </Label>
                  {evidenceUrls.map((url, index) => (
                    <div key={index} className="flex gap-2">
                      <Input
                        value={url}
                        onChange={(e) => updateEvidenceUrl(index, e.target.value)}
                        placeholder={t("report.evidencePlaceholder")}
                      />
                      {evidenceUrls.length > 1 && (
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => removeEvidenceUrl(index)}
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      )}
                    </div>
                  ))}
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={addEvidenceUrl}
                    className="w-full"
                  >
                    <Plus className="w-4 h-4 mr-2" />
                    {t("report.addEvidence")}
                  </Button>
                </div>
                </div>
              </div>

              <div className="flex justify-end gap-2">
                <Button variant="outline" onClick={() => setOpen(false)}>
                  {t("report.cancel")}
                </Button>
                <Button 
                  onClick={handleSubmit} 
                  disabled={
                    !reason || 
                    description.length < 20 || 
                    !contact.trim() || 
                    (evidenceUrls.filter(url => url.trim() !== "").length === 0 && evidenceImages.length === 0) ||
                    uploadingImages ||
                    isSendingCode
                  }
                >
                  {uploadingImages ? t("common.uploading") : isSendingCode ? t("auth.sendingCode") : t("report.submit")}
                </Button>
              </div>
            </>
          ) : verificationStep === "submitting" ? (
            <div className="space-y-4 py-8">
              <div className="flex flex-col items-center justify-center space-y-4">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
                <p className="text-center text-muted-foreground">
                  {t("report.submitting")}
                </p>
              </div>
            </div>
          ) : (
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label>{t("auth.verificationCode")}</Label>
                <div className="flex justify-center">
                  <InputOTP
                    maxLength={4}
                    value={verificationCode}
                    onChange={(value) => setVerificationCode(value)}
                  >
                    <InputOTPGroup>
                      <InputOTPSlot index={0} />
                      <InputOTPSlot index={1} />
                      <InputOTPSlot index={2} />
                      <InputOTPSlot index={3} />
                    </InputOTPGroup>
                  </InputOTP>
                </div>
                <p className="text-xs text-muted-foreground text-center">
                  {t("auth.verificationCodeHint", { email: contact })}
                </p>
              </div>

              <div className="flex justify-center">
                <Button
                  variant="link"
                  size="sm"
                  onClick={handleResendCode}
                  disabled={resendCountdown > 0 || isSubmitting}
                >
                  {resendCountdown > 0
                    ? `${t("auth.resendCode")} (${resendCountdown}s)`
                    : t("auth.resendCode")}
                </Button>
              </div>

              <div className="flex gap-2">
                <Button
                  variant="outline"
                  className="w-full"
                  onClick={() => {
                    setVerificationStep("form");
                    setVerificationCode("");
                  }}
                  disabled={isSubmitting}
                >
                  {t("common.back")}
                </Button>
                <Button
                  className="w-full"
                  onClick={verifyEmailCode}
                  disabled={verificationCode.length !== 4 || isSubmitting}
                >
                  {isSubmitting ? t("auth.verifying") : t("auth.verify")}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      <AlertDialog open={showConfirm} onOpenChange={setShowConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t("report.confirmTitle")}</AlertDialogTitle>
            <AlertDialogDescription>
              {t("report.confirmMessage")}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t("report.cancel")}</AlertDialogCancel>
            <AlertDialogAction onClick={handleConfirmSubmit} disabled={isSubmitting}>
              {isSubmitting ? t("report.submitting") : t("report.submit")}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
};

export default ReportDialog;
